    leadership: { quote: '\u0627\u0644\u062a\u0645\u064a\u0632 \u0644\u064a\u0633 \u0641\u0639\u0644\u0627\u064b \u0639\u0627\u0628\u0631\u0627\u064b\u060c \u0628\u0644 \u0647\u0648 \u0639\u0627\u062f\u0629. \u0641\u064a \u0631\u0648\u0627\u062f \u0627\u0644\u0641\u0643\u0631 \u0627\u0644\u062f\u0648\u0644\u064a\u0629\u060c \u0646\u0624\u0645\u0646 \u0628\u0623\u0646 \u0643\u0644 \u0645\u0624\u0633\u0633\u0629 \u062a\u0645\u062a\u0644\u0643 \u0625\u0645\u0643\u0627\u0646\u064a\u0629 \u062a\u062d\u0642\u064a\u0642 \u0645\u0639\u0627\u064a\u064a\u0631 \u0639\u0627\u0644\u0645\u064a\u0629. \u062f\u0648\u0631\u0646\u0627 \u0647\u0648 \u062a\u0648\u062c\u064a\u0647\u0643 \u0641\u064a \u0647\u0630\u0647 \u0627\u0644\u0631\u062d\u0644\u0629 \u0628\u0627\u0644\u062e\u0628\u0631\u0629 \u0648\u0627\u0644\u062a\u0641\u0627\u0646\u064a.', quoteAr: '\u0627\u0644\u062a\u0645\u064a\u0632 \u0644\u064a\u0633 \u0641\u0639\u0644\u0627\u064b \u0639\u0627\u0628\u0631\u0627\u064b\u060c \u0628\u0644 \u0647\u0648 \u0639\u0627\u062f\u0629. \u0641\u064a \u0631\u0648\u0627\u062f \u0627\u0644\u0641\u0643\u0631 \u0627\u0644\u062f\u0648\u0644\u064a\u0629\u060c \u0646\u0624\u0645\u0646 \u0628\u0623\u0646 \u0643\u0644 \u0645\u0624\u0633\u0633\u0629 \u062a\u0645\u062a\u0644\u0643 \u0625\u0645\u0643\u0627\u0646\u064a\u0629 \u062a\u062d\u0642\u064a\u0642 \u0645\u0639\u0627\u064a\u064a\u0631 \u0639\u0627\u0644\u0645\u064a\u0629.', attribution: '\u0627\u0644\u0645\u0624\u0633\u0633 \u0648\u0627\u0644\u0645\u062f\u064a\u0631 \u0627\u0644\u0639\u0627\u0645' },
    partnerships: { eyebrow: '\u0634\u0631\u0643\u0627\u0624\u0646\u0627', heading: '\u0634\u0631\u0627\u0643\u0627\u062a \u0627\u0633\u062a\u0631\u0627\u062a\u064a\u062c\u064a\u0629', note: '\u0646\u062a\u0639\u0627\u0648\u0646 \u0645\u0639 \u0647\u064a\u0626\u0627\u062a \u0627\u0639\u062a\u0645\u0627\u062f \u0631\u0627\u0626\u062f\u0629 \u0648\u0645\u0646\u0638\u0645\u0627\u062a \u0635\u0646\u0627\u0639\u064a\u0629 \u0644\u062a\u0642\u062f\u064a\u0645 \u0623\u0639\u0644\u0649 \u062c\u0648\u062f\u0629 \u0645\u0646 \u0627\u0644\u062e\u062f\u0645\u0627\u062a.', partners: { aaa: { name: '\u0627\u0639\u062a\u0645\u0627\u062f AAA', desc: '\u0634\u0631\u064a\u0643 \u0627\u0644\u0627\u0639\u062a\u0645\u0627\u062f \u0627\u0644\u0631\u0633\u0645\u064a \u0644\u0634\u0647\u0627\u062f\u0627\u062a \u0623\u0646\u0638\u0645\u0629 \u0627\u0644\u0625\u062f\u0627\u0631\u0629 \u0641\u064a \u062c\u0645\u064a\u0639 \u0623\u0646\u062d\u0627\u0621 \u0627\u0644\u0634\u0631\u0642 \u0627\u0644\u0623\u0648\u0633\u0637.' }, exemplar: { name: '\u0625\u0643\u0632\u064a\u0645\u0628\u0644\u0627\u0631 \u062c\u0644\u0648\u0628\u0627\u0644', desc: '\u0634\u0631\u064a\u0643 \u0627\u0644\u062a\u062f\u0631\u064a\u0628 \u0648\u0627\u0644\u0627\u0639\u062a\u0645\u0627\u062f \u0627\u0644\u062f\u0648\u0644\u064a \u0644\u0628\u0631\u0627\u0645\u062c \u062a\u062f\u0631\u064a\u0628 \u0627\u0644\u0645\u062f\u0642\u0642\u064a\u0646.' }, aeba: { name: 'AEBA', desc: '\u0627\u0644\u062a\u062d\u0627\u0644\u0641 \u0627\u0644\u0639\u0631\u0628\u064a \u0644\u0644\u0645\u0643\u0627\u062a\u0628 \u0627\u0644\u0647\u0646\u062f\u0633\u064a\u0629 - \u0634\u0631\u064a\u0643 \u0625\u0642\u0644\u064a\u0645\u064a \u0644\u0645\u0639\u0627\u064a\u064a\u0631 \u0627\u0644\u0647\u0646\u062f\u0633\u0629 \u0648\u0627\u0644\u0628\u0646\u0627\u0621.' } } },
